SELECT c.post_id, c.title, c.created_at, c.comment_count, c.view_count, m.user_id, m.user_name, CASE WHEN f.post_id IS NOT NULL THEN 1 ELSE 0 END AS isFavorite FROM community c JOIN member m ON c.user_id = m.user_id LEFT JOIN favorite f ON c.post_id = f.post_id AND f.board_type = 'COM' AND f.user_id = #{user_id, jdbcType=VARCHAR}
1=1
ORDER BY post_id DESC OFFSET (#{pageNum} -1) * #{amount} ROWS FETCH NEXT #{amount} ROWS ONLY
